// src/components/Sidebar.js
import React, { useState } from "react";
import { Link, useLocation } from "react-router-dom";
import {
  FaTachometerAlt,
  FaUsers,
  FaBook,
  FaChartBar,
  FaCogs,
  FaFileAlt,
  FaEdit,
  FaUpload,
} from "react-icons/fa";

function Sidebar() {
  const role = localStorage.getItem("role");
  const location = useLocation();
  const [collapsed, setCollapsed] = useState(false);

  // Role-based menu items with icons
  let menu = [];

  if (role === "admin") {
    menu = [
      { name: "Dashboard", path: "/admin", icon: <FaTachometerAlt /> },
      { name: "Manage Users", path: "/admin/users", icon: <FaUsers /> },
      { name: "Manage Courses", path: "/admin/courses", icon: <FaBook /> },
      { name: "Reports", path: "/admin/reports", icon: <FaChartBar /> },
      { name: "Settings", path: "/admin/settings", icon: <FaCogs /> },
    ];
  } else if (role === "instructor") {
    menu = [
      { name: "Dashboard", path: "/instructor", icon: <FaTachometerAlt /> },
      { name: "My Courses", path: "/instructor/courses", icon: <FaBook /> },
      { name: "Assignments", path: "/instructor/assignments", icon: <FaFileAlt /> },
      { name: "Students", path: "/instructor/students", icon: <FaUsers /> },
    ];
  } else if (role === "student") {
    menu = [
      { name: "Dashboard", path: "/student", icon: <FaTachometerAlt /> },
      { name: "My Courses", path: "/student/courses", icon: <FaBook /> },
      { name: "Assignments", path: "/student/assignments", icon: <FaFileAlt /> },
      { name: "Grades", path: "/student/grades", icon: <FaChartBar /> },
    ];
  } else if (role === "content") {
    menu = [
      { name: "Dashboard", path: "/content", icon: <FaTachometerAlt /> },
      { name: "Create Content", path: "/content/create", icon: <FaUpload /> },
      { name: "Edit Content", path: "/content/edit", icon: <FaEdit /> },
      { name: "Published Materials", path: "/content/published", icon: <FaBook /> },
    ];
  }

  return (
    <div
      className={`d-flex flex-column bg-dark text-white p-3 sidebar`}
      style={{
        minHeight: "100vh",
        width: collapsed ? "70px" : "220px",
        transition: "width 0.3s",
      }}
    >
      {/* Collapse Button */}
      <button
        onClick={() => setCollapsed(!collapsed)}
        className="btn btn-sm btn-light mb-3 align-self-center"
        style={{ width: collapsed ? "40px" : "100%" }}
      >
        {collapsed ? "➡️" : "⬅️ Collapse"}
      </button>

      {/* Role Label */}
      <h6 className="text-center mb-4" style={{ fontSize: collapsed ? "0.7rem" : "1rem" }}>
        {role?.toUpperCase()}
      </h6>

      {/* Menu Links */}
      {menu.map((item, idx) => (
        <Link
          key={idx}
          to={item.path}
          className={`d-flex align-items-center text-white text-decoration-none mb-2 p-2 rounded ${
            location.pathname === item.path ? "bg-primary" : "hover-bg"
          }`}
          style={{ transition: "0.3s" }}
        >
          <span style={{ fontSize: "1.1rem", width: "30px", textAlign: "center" }}>
            {item.icon}
          </span>
          {!collapsed && <span className="ms-2">{item.name}</span>}
        </Link>
      ))}
    </div>
  );
}

export default Sidebar;
